






import Vue from "vue";

export default Vue.extend({
  /*
    tag: ['div', 'li', 'tr' ...]
    type: ['Bootstrap', 'Custom', 'Table']
  */
  props: {
    tag: {
      type: String,
      default: 'div',
    },
    isHeading: {
      type: Boolean,
      default: false,
    },
    group: {
      type: Boolean,
      default: false,
    },
    spacing: {
      type: Number,
      default: 0,
    },
    integrate: {
      type: Boolean,
      default: false,
    },
    squareTag: {
      type: Boolean,
      default: false,
    },
    tableElement: {
      type: Boolean,
      default: false,
    },
  },
  computed: {
    classes():Array<string> {
      return [
        {
          'nano-group': this.group,
          'integrate': this.integrate,
        },
        this.computedSpacing
      ]
    },
    computedSpacing():string {
      let space = this.spacing;
      space = space > 400 ? 400 : space;
      space = space < 0 ? 0 : space;
      return space === 0 ? '' : `sp${space}`;
    },
    role():string {
      if(this.tableElement){
        let result = 'row';
        if(this.group || this.squareTag) {
          result = 'group';
        }
        return result;
      } else {
        return "";
      }
    },
  },
});
